import { AsyncStorage } from 'react-native';

// Function to generate a random token
function generateToken() {
  return Math.random().toString(36).substring(2);
}

// Function to save the generated token in async storage
async function saveTokenToLocalStorage(token) {
  try {
    await AsyncStorage.setItem('@session_token', token);
  } catch (error) {
    console.log("Error saving data", error);
  }
}

// Function to get the token from async storage
async function getTokenFromLocalStorage() {
  try {
    const value = await AsyncStorage.getItem('@session_token');
    if(value !== null) {
      return value;
    }
  } catch (error) {
    console.log("Error retrieving data", error);
  }
}

// Function to delete the token from async storage when user logs out
async function removeTokenFromLocalStorage() {
  try {
    await AsyncStorage.removeItem('@session_token');
  } catch (error) {
    console.log("Error deleting data", error);
  }
}